              <svg width="68" height="68" viewBox="0 0 68 68" style="position:absolute;inset:0;"><circle cx="34" cy="34" r="28" fill="none" stroke="rgba(15,23,42,.09)" stroke-width="6"></circle><circle data-ref="pRingRef" cx="34" cy="34" r="28" fill="none" stroke="url(#ring-grad)" stroke-width="6" stroke-linecap="round" transform="rotate(-90 34 34)" style="stroke-dasharray:176;stroke-dashoffset:176;"></circle></svg>
